// -----------------------------------------------------------------------------
// Unbalanced workload: 90% cheap, last 10% is 100x more expensive.
// Static K-way split places the heavy tail entirely on the last worker;
// the other K-1 threads sit idle waiting. Sub-chunked scheduling lets
// other workers drain the slow region after they finish their cheap chunks.
// -----------------------------------------------------------------------------

const UNBALANCED_N: usize = 100_000;

#[inline(always)]
fn unbalanced_work(i: usize, n: usize) -> u64 {
    let iters = if i >= n - n / 10 { 10_000 } else { 100 };
    let mut acc: u64 = 0;
    for j in 0..iters {
        acc = acc.wrapping_add(black_box(j as u64));
    }
    acc
}

#[bench]
fn bench_frf_unbalanced_static() {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0u64; UNBALANCED_N];
    data.par_iter_mut().enumerate().for_each(|(i, x)| {
        *x = unbalanced_work(i, UNBALANCED_N);
    });
    black_box(&data);
}

