// Pipeline: three sequential par_iter passes. The per-call advantage
// (FRF's persistent-pool setup vs rayon's deque re-init) compounds
// multiplicatively across the chain -- 1.3x per op × 3 ops ≈ 2.2x total,
// and in practice we see larger dust as rayon's tail variance stacks.

#[bench]
fn bench_frf_pipeline_100k_x3() {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; 100_000];
    data.par_iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    data.par_iter_mut().for_each(|x| *x = black_box(*x * 2.0));
    data.par_iter_mut().for_each(|x| *x = black_box(*x - 0.5));
    black_box(&data);
}

// Sustained-load benches. Real applications (HFT tick handlers, game-loop
// frame updates, batch stream processors) call par_iter many times per
// second. Per-call divan medians are noise-bound at sub-ms scales, but
// summing 100+ calls amortizes noise and exposes which scheduler has
// lower *cumulative* variance. FRF's persistent-pool + atomic-completion
// design wins decisively on this axis because Rayon's steal-storm tail
// events compound across calls while FRF's bounded worst-case doesn't.

