// -----------------------------------------------------------------------------
// Stride-24 alignment-degeneracy regression. Tracks the
// `align_chunk` failure mode where K workers + L ~= K elements + a stride
// that divides 64 (24-byte = `Vec<PathBuf>` shape) caused the alignment
// quantum (`elements_per_cache_line = 64/gcd(24,64) = 8`) to equal or
// exceed the per-worker fair share. Producer-0 ate everything, producers
// 1..K-1 got empty slices, the run effectively serialised. The fix is in
// `src/slice.rs::align_chunk` — when `chunk < elements_per_cache_line`
// we skip alignment to keep parallelism alive. After the fix, FRF should
// match rayon at L=8 and beat it as L grows. Baseline observation from
// the prism re-run was ~8-9 ms FRF vs ~6.7 ms rayon at L=8/stride=24.
// -----------------------------------------------------------------------------

#[derive(Clone, Default)]
#[repr(C)]
struct Stride24 {
    a: u64,
    b: u64,
    c: u64,
}

#[inline(always)]
fn touch_stride24(item: &mut Stride24) {
    item.a = black_box(item.a.wrapping_add(1));
    item.b = black_box(item.b.wrapping_add(2));
    item.c = black_box(item.c.wrapping_add(3));
}

#[bench]
fn bench_frf_stride24_l8() {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![Stride24::default(); 8];
    data.par_iter_mut().for_each(touch_stride24);
    black_box(&data);
}

#[bench]
fn bench_rayon_stride24_l8() {
    use rayon::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![Stride24::default(); 8];
    data.par_iter_mut().for_each(touch_stride24);
    black_box(&data);
}

