// -----------------------------------------------------------------------------
// Within-chunk stealing regression target: 5%-tail unbalanced workload at
// 100k and 1M elements. Per the README's roadmap item #3, this is the regime
// where rayon's deque-based mid-flight subdivision had a structural edge over
// FRF's static partitioning. The two-level mini-batch scheduler was added so
// idle workers can CAS-steal mini-batches from chunks whose owner is still
// chewing on a 100x-cost run of items.
//
// Acceptance bar: at 1M, FRF should reach within 1.5x of rayon's median (was
// 1.3x at 1M before stealing on a slightly different bench shape). The shape
// matches the prompt: 5% of items take 100x the work of the rest.
// -----------------------------------------------------------------------------

#[inline(never)]
fn unbalanced_sum_workload(work: &[u64]) -> u64 {
    use gnosis_frf::prelude::*;
    work.par_iter()
        .map(|&w| {
            let mut s = 0u64;
            for _ in 0..w {
                s = black_box(s.wrapping_add(1));
            }
            s
        })
        .with_sub_chunks_auto()
        .reduce(|| 0u64, |a, b| a.wrapping_add(b))
}

#[inline(never)]
fn closed_loop_representative_sum_workload(
    work: &[u64],
    certificate: gnosis_frf::prelude::ClosedLoopWorkloadShapeCertificate,
) -> u64 {
    use gnosis_frf::prelude::*;
    let weight_certificate = certificate.weight_accumulation();
    work.par_iter()
        .map(|&w| closed_loop_weight_accumulation_value(w, weight_certificate))
        .with_sub_chunks_auto()
        .reduce(|| 0u64, |a, b| a.wrapping_add(b))
}

#[inline(never)]
fn rayon_unbalanced_sum_workload(work: &[u64]) -> u64 {
    use rayon::prelude::*;
    work.par_iter()
        .map(|&w| {
            let mut s = 0u64;
            for _ in 0..w {
                s = black_box(s.wrapping_add(1));
            }
            s
        })
        .sum()
}

fn make_unbalanced_work(n: usize) -> Vec<u64> {
    (0..n).map(|i| if i < n / 20 { 100 } else { 1 }).collect()
}

fn closed_loop_candidate_probe(
    work: &[u64],
    runtime_source: &str,
    counts: &mut ClosedLoopProbeCounts,
) -> u64 {
    use gnosis_frf::prelude::*;

    let workload_certificate = exact_closed_loop_repeated_unit_workload_certificate();
    let decision = execute_closed_loop_runtime_candidate(
        runtime_source,
        || unbalanced_sum_workload(work),
        || closed_loop_representative_sum_workload(work, workload_certificate),
    );

    if decision.certified_loop {
        counts.certified += 1;
    } else {
        counts.fallback += 1;
    }
    match decision.selected_path {
        ClosedLoopExecutionPath::ExperimentalClosedLoop => {
            counts.selected_experimental += 1;
        }
        ClosedLoopExecutionPath::Normal => {
            counts.selected_normal += 1;
        }
    }
    if !decision.equivalent_outputs {
        counts.divergent += 1;
    }

    decision.output
}

fn closed_loop_single_run_probe(
    work: &[u64],
    runtime_source: &str,
    counts: &mut ClosedLoopProbeCounts,
) -> u64 {
    use gnosis_frf::prelude::*;

    let workload_certificate = exact_closed_loop_repeated_unit_workload_certificate();
    let decision = execute_closed_loop_runtime_single_run_candidate(
        runtime_source,
        workload_certificate,
        || unbalanced_sum_workload(work),
        |certificate| closed_loop_representative_sum_workload(work, certificate),
    );

    if decision.certified_loop {
        counts.certified += 1;
    } else {
        counts.fallback += 1;
    }
    match decision.selected_path {
        ClosedLoopExecutionPath::ExperimentalClosedLoop => {
            counts.selected_experimental += 1;
        }
        ClosedLoopExecutionPath::Normal => {
            counts.selected_normal += 1;
        }
    }
    if !decision.eligible_workload {
        counts.divergent += 1;
    }

    decision.output
}

#[divan::bench(args = [100_000, 1_000_000])]
fn bench_frf_unbalanced(bencher: divan::Bencher, n: usize) {
    let work = make_unbalanced_work(n);
    bencher.bench(|| black_box(unbalanced_sum_workload(&work)));
}

