// for_each variant of the same shape — exercises the stealing path on the
// for_each executor (where the within-chunk stealing implementation lives).
fn unbalanced_for_each_workload(work: &[u64], out: &mut [u64]) {
    use gnosis_frf::prelude::*;
    out.par_iter_mut()
        .zip(work.par_iter())
        .with_sub_chunks_auto()
        .for_each(|(o, &w)| {
            let mut s = 0u64;
            for _ in 0..w {
                s = s.wrapping_add(1);
            }
            *o = s;
        });
}

fn rayon_unbalanced_for_each_workload(work: &[u64], out: &mut [u64]) {
    use rayon::prelude::*;
    out.par_iter_mut().zip(work.par_iter()).for_each(|(o, &w)| {
        let mut s = 0u64;
        for _ in 0..w {
            s = s.wrapping_add(1);
        }
        *o = s;
    });
}

#[divan::bench(args = [100_000, 1_000_000])]
fn bench_frf_unbalanced_for_each(bencher: divan::Bencher, n: usize) {
    let work = make_unbalanced_work(n);
    let mut out = vec![0u64; n];
    bencher.bench_local(|| {
        unbalanced_for_each_workload(&work, &mut out);
        black_box(&out);
    });
}

#[divan::bench(args = [100_000, 1_000_000])]
fn bench_rayon_unbalanced_for_each(bencher: divan::Bencher, n: usize) {
    let work = make_unbalanced_work(n);
    let mut out = vec![0u64; n];
    bencher.bench_local(|| {
        rayon_unbalanced_for_each_workload(&work, &mut out);
        black_box(&out);
    });
}
